import React from 'react';
import { graphql } from 'gatsby';
import { GatsbyImage } from 'gatsby-plugin-image';
import Layout from '../components/layout';
import SectionMenu from '../components/sections/menu';
import Grid from '@mui/material/Grid';
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';

export default function WorksTemplate({ data }) {
  return (
    <Layout>
      <SectionMenu />
      <Grid
        container
        justifyContent='center'
        spacing={4}
        mt={6} // spacing 分を引く
      >
        <Grid item md={6} xs={12}>
          <Box
            sx={{
              width: '75%',
              mx: 'auto',
              pointerEvents: 'none',
              userSelect: 'none'
            }}
            onClick={e => e.preventDefault()}
            onMouseDown={e => e.preventDefault()}
            onMouseUp={e => e.preventDefault()}
            onContextMenu={e => {
              e.preventDefault();
            }}
          >
            <GatsbyImage
              image={data.imageSharp.gatsbyImageData}
              alt='Yuhei Ono'
              placeholder='blurred'
              style={{
                pointerEvents: 'none',
                userSelect: 'none'
              }}
            />
          </Box>
        </Grid>
        <Grid item md={6} xs={12}>
          <Box
            sx={{
              display: 'flex',
              justifyContent: 'center',
              alignItems: 'center',
              height: '100%'
            }}
          >
            <Box sx={{ width: '75%' }}>
              <Box>
                <Typography variant='h5'>Yuhei Ono</Typography>
                <Typography>Photographer</Typography>
              </Box>
              <Box mt={6}>
                <Typography mb={4}>写真家 小野 悠平</Typography>
                <Typography my={2}>1990年 兵庫県神戸市生まれ</Typography>
                <Typography my={2}>甲南大学 法学部 卒業</Typography>
                <Typography my={2}>
                  ビジュアルアーツ専門学校大阪 写真学科 卒業
                </Typography>
                <Typography my={2}>博報堂プロダクツ 入社</Typography>
                <Typography mt={2} mb={4}>
                  退社後、インテリアやホテルの撮影を中心に関西を拠点に活動中
                </Typography>
              </Box>
            </Box>
          </Box>
        </Grid>
      </Grid>
    </Layout>
  );
}

export const pageQuery = graphql`
  {
    imageSharp(fluid: { originalName: { eq: "profile.jpg" } }) {
      gatsbyImageData
    }
  }
`;
